    S1 = #{package => F@_1, requirement => F@_2},
    S2 = if F@_3 == '$undef' -> S1;
            true -> S1#{optional => F@_3}
         end,
    S3 = if F@_4 == '$undef' -> S2;
            true -> S2#{app => F@_4}
         end,
    if F@_5 == '$undef' -> S3;
       true -> S3#{repository => F@_5}
    end;
